document.addEventListener("DOMContentLoaded",()=>{Array.prototype.slice.call(document.querySelectorAll(".navbar-burger"),0).forEach(e=>{e.addEventListener("click",()=>{const a=e.dataset.target,r=document.getElementById(a);e.classList.toggle("is-active"),r.classList.toggle("is-active")})});const t=document.querySelector(".carousel");t&&typeof Flickity!="undefined"&&(Flickity.data(t)||new Flickity(t,{setGallerySize:!0,imagesLoaded:!0,cellAlign:"left",contain:!0,autoPlay:4500,wrapAround:!0,pauseAutoPlayOnHover:!1})).playPlayer()});
